svg.script:
class PerlinNoise {
  constructor(seed = Math.random() * 10000) {
    this.p = [];
    for (let i = 0; i < 256; i++) this.p[i] = i;
    let n = seed;
    for (let i = 255; i > 0; i--) {
      n = (n * 16807) % 2147483647;
      const j = n % (i + 1);
      [this.p[i], this.p[j]] = [this.p[j], this.p[i]];
    }
    this.p = this.p.concat(this.p);
  }
  fade(t) { return t * t * t * (t * (t * 6 - 15) + 10); }
  lerp(a, b, t) { return a + t * (b - a); }
  grad(hash, x) { return (hash & 1) === 0 ? x : -x; }
  noise1D(x) {
    const xi = Math.floor(x) & 255;
    const xf = x - Math.floor(x);
    const u = this.fade(xf);
    return this.lerp(this.grad(this.p[xi], xf), this.grad(this.p[xi + 1], xf - 1), u);
  }
}

const keyPositions = [
  { x: 40.5, y: 78 }, { x: 55.5, y: 78 }, { x: 70.5, y: 78 }, { x: 85.5, y: 78 },
  { x: 100.5, y: 78 }, { x: 115.5, y: 78 }, { x: 130.5, y: 78 }, { x: 145.5, y: 78 }, { x: 160.5, y: 78 },
  { x: 43.5, y: 89 }, { x: 58.5, y: 89 }, { x: 73.5, y: 89 }, { x: 88.5, y: 89 },
  { x: 103.5, y: 89 }, { x: 118.5, y: 89 }, { x: 133.5, y: 89 }, { x: 148.5, y: 89 },
  { x: 46.5, y: 100 }, { x: 61.5, y: 100 }, { x: 95, y: 100 },
  { x: 128.5, y: 100 }, { x: 143.5, y: 100 }, { x: 158.5, y: 100 }
];

const clauditoX = 100;
const clauditoY = 18;

function lerp(a, b, t) {
  return a + (b - a) * t;
}

// Easing function for smooth acceleration/deceleration
function easeInOutQuad(t) {
  return t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2;
}

const legs = [
  {
    el: document.getElementById('leg0'),
    noise: new PerlinNoise(1),
    anchorX: -16,
    anchorY: 32,
    width: 4,
    targetKeys: keyPositions.filter(k => k.x < 75),
    phase: 0,
    // Current interpolated position
    currentX: 60,
    currentY: 85,
    // Target position
    targetX: 60,
    targetY: 85,
    // Timing for key switches
    lastSwitchTime: 0,
    switchInterval: 0.3,  // seconds between key changes
    transitionSpeed: 12   // higher = faster movement
  },
  {
    el: document.getElementById('leg1'),
    noise: new PerlinNoise(2),
    anchorX: -10,
    anchorY: 32,
    width: 4,
    targetKeys: keyPositions.filter(k => k.x >= 55 && k.x < 100),
    phase: 0.7,
    currentX: 80,
    currentY: 85,
    targetX: 80,
    targetY: 85,
    lastSwitchTime: 0,
    switchInterval: 0.25,
    transitionSpeed: 14
  },
  {
    el: document.getElementById('leg2'),
    noise: new PerlinNoise(3),
    anchorX: 6,
    anchorY: 32,
    width: 4,
    targetKeys: keyPositions.filter(k => k.x >= 85 && k.x < 135),
    phase: 1.5,
    currentX: 110,
    currentY: 85,
    targetX: 110,
    targetY: 85,
    lastSwitchTime: 0,
    switchInterval: 0.28,
    transitionSpeed: 13
  },
  {
    el: document.getElementById('leg3'),
    noise: new PerlinNoise(4),
    anchorX: 12,
    anchorY: 32,
    width: 4,
    targetKeys: keyPositions.filter(k => k.x >= 115),
    phase: 2.2,
    currentX: 140,
    currentY: 85,
    targetX: 140,
    targetY: 85,
    lastSwitchTime: 0,
    switchInterval: 0.32,
    transitionSpeed: 11
  }
];

let time = 0;
let lastTime = performance.now();

function animate(currentTime) {
  // Skip animation when paused (set by parent page's IntersectionObserver)
  if (window.isPaused) {
    lastTime = currentTime;
    requestAnimationFrame(animate);
    return;
  }
  const deltaTime = (currentTime - lastTime) / 1000;
  lastTime = currentTime;
  time += deltaTime;

  legs.forEach(leg => {
    // Check if it's time to pick a new target key
    if (time - leg.lastSwitchTime > leg.switchInterval) {
      leg.lastSwitchTime = time;

      // Use noise to pick next key (biased toward nearby keys)
      const noiseVal = leg.noise.noise1D(time * 0.8 + leg.phase);
      const keyIndex = Math.floor((noiseVal * 0.5 + 0.5) * leg.targetKeys.length);
      const newTarget = leg.targetKeys[Math.min(keyIndex, leg.targetKeys.length - 1)];

      leg.targetX = newTarget.x;
      leg.targetY = newTarget.y;

      // Randomize next switch interval slightly
      leg.switchInterval = 0.2 + leg.noise.noise1D(time + 50) * 0.15 + 0.1;
    }

    // Smoothly interpolate current position toward target
    const lerpFactor = 1 - Math.exp(-leg.transitionSpeed * deltaTime);
    leg.currentX = lerp(leg.currentX, leg.targetX, lerpFactor);
    leg.currentY = lerp(leg.currentY, leg.targetY, lerpFactor);

    // Calculate leg geometry from anchor to current position
    const anchorGlobalX = clauditoX + leg.anchorX + leg.width / 2;
    const anchorGlobalY = clauditoY + leg.anchorY;

    const dx = leg.currentX - anchorGlobalX;
    const dy = leg.currentY - anchorGlobalY;

    const length = Math.sqrt(dx * dx + dy * dy);
    const angle = Math.atan2(dx, dy) * (180 / Math.PI);

    // Add subtle noise wobble
    const wobble = leg.noise.noise1D(time * 4 + leg.phase) * 2;
    const stretchWobble = leg.noise.noise1D(time * 3 + leg.phase + 100) * 2;

    leg.el.setAttribute('height', length + stretchWobble);

    const originX = leg.anchorX + leg.width / 2;
    const originY = leg.anchorY;
    leg.el.setAttribute('transform', `rotate(${angle + wobble}, ${originX}, ${originY})`);
  });

  requestAnimationFrame(animate);
}

requestAnimationFrame(animate);
